using InventoryFlow.Domain.Common;
using InventoryFlow.Domain.Exceptions;

namespace InventoryFlow.Domain.Entities;

/// <summary>An immutable posted single-line sales fulfillment.</summary>
public sealed class SalesFulfillment : Entity<Guid>
{
    public SalesFulfillment(Guid id, Guid workspaceId, Guid warehouseId, Guid productId, decimal quantity,
        string idempotencyKey, Guid inventoryMovementId, DateTimeOffset fulfilledAtUtc) : base(id)
    {
        if (id == Guid.Empty || workspaceId == Guid.Empty || warehouseId == Guid.Empty || productId == Guid.Empty ||
            inventoryMovementId == Guid.Empty)
            throw new DomainException("Sales fulfillment identifiers are required.");
        if (fulfilledAtUtc.Offset != TimeSpan.Zero) throw new DomainException("Sales fulfillment time must be in UTC.");
        WorkspaceId = workspaceId;
        WarehouseId = warehouseId;
        ProductId = productId;
        Quantity = InventoryMovement.ValidateQuantity(quantity);
        IdempotencyKey = InventoryMovement.NormalizeIdempotencyKey(idempotencyKey);
        InventoryMovementId = inventoryMovementId;
        FulfilledAtUtc = fulfilledAtUtc;
    }

    public Guid WorkspaceId { get; private set; }
    public Guid WarehouseId { get; private set; }
    public Guid ProductId { get; private set; }
    public decimal Quantity { get; private set; }
    public string IdempotencyKey { get; private set; }
    public Guid InventoryMovementId { get; private set; }
    public DateTimeOffset FulfilledAtUtc { get; private set; }
}

using System.Text.Json.Serialization;
using InventoryFlow.Domain.Entities;

namespace InventoryFlow.Application.Features.Sales;

public sealed record RecordSalesFulfillmentRequest(Guid WarehouseId, Guid ProductId,
    [property: JsonNumberHandling(JsonNumberHandling.AllowReadingFromString)] decimal Quantity, string IdempotencyKey);

public sealed record RecordSalesFulfillmentCommand(Guid WorkspaceId, Guid WarehouseId, Guid ProductId, decimal Quantity,
    string IdempotencyKey) : MediatR.IRequest<SalesFulfillmentResponse?>;

public sealed record ListSalesFulfillmentsQuery(Guid WorkspaceId) : MediatR.IRequest<IReadOnlyList<SalesFulfillmentResponse>>;

public sealed record SalesFulfillmentResponse(Guid Id, Guid WarehouseId, Guid ProductId, decimal Quantity,
    Guid InventoryMovementId, DateTimeOffset FulfilledAtUtc)
{
    public static SalesFulfillmentResponse From(SalesFulfillment fulfillment) => new(fulfillment.Id, fulfillment.WarehouseId,
        fulfillment.ProductId, fulfillment.Quantity, fulfillment.InventoryMovementId, fulfillment.FulfilledAtUtc);
}

public interface ISalesFulfillmentService
{
    Task<SalesFulfillment?> RecordAsync(Guid workspaceId, Guid warehouseId, Guid productId, decimal quantity, string idempotencyKey,
        DateTimeOffset fulfilledAtUtc, CancellationToken cancellationToken);
    Task<IReadOnlyList<SalesFulfillment>> ListAsync(Guid workspaceId, CancellationToken cancellationToken);
}

using MediatR;

namespace InventoryFlow.Application.Features.Sales;

public sealed class RecordSalesFulfillmentHandler(ISalesFulfillmentService service, TimeProvider timeProvider)
    : IRequestHandler<RecordSalesFulfillmentCommand, SalesFulfillmentResponse?>
{
    public async Task<SalesFulfillmentResponse?> Handle(RecordSalesFulfillmentCommand request, CancellationToken cancellationToken)
    {
        var fulfillment = await service.RecordAsync(request.WorkspaceId, request.WarehouseId, request.ProductId, request.Quantity,
            request.IdempotencyKey, timeProvider.GetUtcNow(), cancellationToken);
        return fulfillment is null ? null : SalesFulfillmentResponse.From(fulfillment);
    }
}

public sealed class ListSalesFulfillmentsHandler(ISalesFulfillmentService service)
    : IRequestHandler<ListSalesFulfillmentsQuery, IReadOnlyList<SalesFulfillmentResponse>>
{
    public async Task<IReadOnlyList<SalesFulfillmentResponse>> Handle(ListSalesFulfillmentsQuery request,
        CancellationToken cancellationToken) =>
        (await service.ListAsync(request.WorkspaceId, cancellationToken)).Select(SalesFulfillmentResponse.From).ToArray();
}

using FluentValidation;
using InventoryFlow.Domain.Entities;

namespace InventoryFlow.Application.Features.Sales;

public sealed class RecordSalesFulfillmentCommandValidator : AbstractValidator<RecordSalesFulfillmentCommand>
{
    public RecordSalesFulfillmentCommandValidator()
    {
        RuleFor(x => x.WorkspaceId).NotEmpty();
        RuleFor(x => x.WarehouseId).NotEmpty();
        RuleFor(x => x.ProductId).NotEmpty();
        RuleFor(x => x.Quantity).GreaterThan(0m).Must(quantity => decimal.Round(quantity, 4) == quantity)
            .WithMessage("Quantity must have at most four decimal places.")
            .LessThanOrEqualTo(InventoryMovement.MaxQuantity).WithMessage("Quantity must not exceed 99999999999999.9999.");
        RuleFor(x => x.IdempotencyKey).NotEmpty().MaximumLength(InventoryMovement.IdempotencyKeyMaxLength);
    }
}

using InventoryFlow.Domain.Entities;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

namespace InventoryFlow.Infrastructure.Persistence.Configurations;

public sealed class SalesFulfillmentConfiguration : IEntityTypeConfiguration<SalesFulfillment>
{
    public void Configure(EntityTypeBuilder<SalesFulfillment> builder)
    {
        builder.ToTable("SalesFulfillments");
        builder.HasKey(fulfillment => fulfillment.Id);
        builder.Property(fulfillment => fulfillment.Quantity).HasPrecision(18, 4).IsRequired();
        builder.Property(fulfillment => fulfillment.IdempotencyKey).HasMaxLength(InventoryMovement.IdempotencyKeyMaxLength).IsRequired();
        builder.Property(fulfillment => fulfillment.FulfilledAtUtc).IsRequired();
        builder.HasIndex(fulfillment => new { fulfillment.WorkspaceId, fulfillment.IdempotencyKey }).IsUnique();
        builder.HasIndex(fulfillment => fulfillment.InventoryMovementId).IsUnique();
        builder.HasIndex(fulfillment => new { fulfillment.WorkspaceId, fulfillment.FulfilledAtUtc, fulfillment.Id });
        builder.HasOne<Workspace>().WithMany().HasForeignKey(fulfillment => fulfillment.WorkspaceId).OnDelete(DeleteBehavior.Cascade);
        builder.HasOne<Warehouse>().WithMany().HasForeignKey(fulfillment => fulfillment.WarehouseId).OnDelete(DeleteBehavior.Restrict);
        builder.HasOne<Product>().WithMany().HasForeignKey(fulfillment => fulfillment.ProductId).OnDelete(DeleteBehavior.Restrict);
        builder.HasOne<InventoryMovement>().WithMany().HasForeignKey(fulfillment => fulfillment.InventoryMovementId).OnDelete(DeleteBehavior.Restrict);
    }
}

using System.Data;
using InventoryFlow.Application.Features.Sales;
using InventoryFlow.Domain.Entities;
using InventoryFlow.Infrastructure.Inventory;
using InventoryFlow.Infrastructure.Persistence;
using Microsoft.EntityFrameworkCore;

namespace InventoryFlow.Infrastructure.Sales;

/// <summary>Posts immutable sales fulfillments and their issue ledger entries in one transaction.</summary>
public sealed class EfSalesFulfillmentService(ApplicationDbContext dbContext) : ISalesFulfillmentService
{
    public async Task<SalesFulfillment?> RecordAsync(Guid workspaceId, Guid warehouseId, Guid productId, decimal quantity,
        string idempotencyKey, DateTimeOffset fulfilledAtUtc, CancellationToken cancellationToken)
    {
        quantity = InventoryMovement.ValidateQuantity(quantity);
        idempotencyKey = InventoryMovement.NormalizeIdempotencyKey(idempotencyKey);
        var strategy = dbContext.Database.CreateExecutionStrategy();
        return await strategy.ExecuteAsync(async () =>
        {
            await using var transaction = await dbContext.Database.BeginTransactionAsync(IsolationLevel.Serializable, cancellationToken);
            var existing = await dbContext.SalesFulfillments.SingleOrDefaultAsync(fulfillment => fulfillment.WorkspaceId == workspaceId &&
                fulfillment.IdempotencyKey == idempotencyKey, cancellationToken);
            if (existing is not null)
            {
                await transaction.CommitAsync(cancellationToken);
                return existing;
            }

            var fulfillmentId = Guid.NewGuid();
            var movement = await new InventoryLedgerWriter(dbContext).RecordAsync(workspaceId, warehouseId, productId,
                InventoryMovementType.Issue, quantity, fulfillmentId.ToString("N"), fulfilledAtUtc, Guid.NewGuid(), cancellationToken);
            if (movement is null)
            {
                await transaction.RollbackAsync(cancellationToken);
                return null;
            }

            var fulfillment = new SalesFulfillment(fulfillmentId, workspaceId, warehouseId, productId, quantity, idempotencyKey,
                movement.Id, fulfilledAtUtc);
            dbContext.SalesFulfillments.Add(fulfillment);
            await dbContext.SaveChangesAsync(cancellationToken);
            await transaction.CommitAsync(cancellationToken);
            return fulfillment;
        });
    }

    public async Task<IReadOnlyList<SalesFulfillment>> ListAsync(Guid workspaceId, CancellationToken cancellationToken) =>
        await dbContext.SalesFulfillments.AsNoTracking().Where(fulfillment => fulfillment.WorkspaceId == workspaceId)
            .OrderByDescending(fulfillment => fulfillment.FulfilledAtUtc).ThenByDescending(fulfillment => fulfillment.Id)
            .ToListAsync(cancellationToken);
}

using InventoryFlow.Application.Common.Tenancy;
using InventoryFlow.Application.Features.Sales;
using MediatR;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;

namespace InventoryFlow.Api.Controllers;

[ApiController]
[Authorize]
[Route("api/sales/fulfillments")]
public sealed class SalesFulfillmentsController(ISender sender, ICurrentWorkspace currentWorkspace) : ControllerBase
{
    [HttpPost]
    [ProducesResponseType<SalesFulfillmentResponse>(StatusCodes.Status201Created)]
    [ProducesResponseType(StatusCodes.Status403Forbidden)]
    [ProducesResponseType(StatusCodes.Status404NotFound)]
    public async Task<ActionResult<SalesFulfillmentResponse>> Record(RecordSalesFulfillmentRequest request,
        [FromHeader(Name = "Idempotency-Key")] string? idempotencyKey, CancellationToken cancellationToken)
    {
        var workspace = await currentWorkspace.GetAsync(cancellationToken);
        if (workspace is null) return Forbid();
        var fulfillment = await sender.Send(new RecordSalesFulfillmentCommand(workspace.Id, request.WarehouseId, request.ProductId,
            request.Quantity, idempotencyKey ?? request.IdempotencyKey), cancellationToken);
        return fulfillment is null ? NotFound() : Created($"/api/sales/fulfillments/{fulfillment.Id}", fulfillment);
    }

    [HttpGet]
    [ProducesResponseType<IReadOnlyList<SalesFulfillmentResponse>>(StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status403Forbidden)]
    public async Task<ActionResult<IReadOnlyList<SalesFulfillmentResponse>>> List(CancellationToken cancellationToken)
    {
        var workspace = await currentWorkspace.GetAsync(cancellationToken);
        if (workspace is null) return Forbid();
        return Ok(await sender.Send(new ListSalesFulfillmentsQuery(workspace.Id), cancellationToken));
    }
}

